import{_ as e,o as a,c as d,aA as i}from"./chunks/framework.CebKgM-l.js";const y=JSON.parse('{"title":"Face name aliases","description":"","frontmatter":{},"headers":[],"relativePath":"krk/aliases.md","filePath":"krk/aliases.md","lastUpdated":null}'),o={name:"krk/aliases.md"};function r(s,t,l,n,c,h){return a(),d("div",null,[...t[0]||(t[0]=[i('<h1 id="Face-name-aliases" tabindex="-1">Face name aliases <a class="header-anchor" href="#Face-name-aliases" aria-label="Permalink to &quot;Face name aliases {#Face-name-aliases}&quot;">​</a></h1><p>Face names in <code>Boundary</code> directives depend on the lattice dimensionality. This page documents the public names for this branch and the parser-only aliases that should not be treated as supported runtime features.</p><h2 id="Base-2D-names-D2Q9" tabindex="-1">Base 2D names (D2Q9) <a class="header-anchor" href="#Base-2D-names-D2Q9" aria-label="Permalink to &quot;Base 2D names (D2Q9) {#Base-2D-names-D2Q9}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Face</th><th style="text-align:right;">Position</th></tr></thead><tbody><tr><td style="text-align:right;"><code>west</code></td><td style="text-align:right;"><code>x = 0</code></td></tr><tr><td style="text-align:right;"><code>east</code></td><td style="text-align:right;"><code>x = Lx</code></td></tr><tr><td style="text-align:right;"><code>south</code></td><td style="text-align:right;"><code>y = 0</code></td></tr><tr><td style="text-align:right;"><code>north</code></td><td style="text-align:right;"><code>y = Ly</code></td></tr><tr><td style="text-align:right;"><code>front</code> / <code>back</code></td><td style="text-align:right;">legacy aliases</td></tr></tbody></table><p>3D-only names such as <code>top</code> and <code>bottom</code> are rejected on D2Q9 by <code>_validate_faces_vs_lattice</code>.</p><h2 id="Additional-3D-names-D3Q19" tabindex="-1">Additional 3D names (D3Q19) <a class="header-anchor" href="#Additional-3D-names-D3Q19" aria-label="Permalink to &quot;Additional 3D names (D3Q19) {#Additional-3D-names-D3Q19}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Face</th><th style="text-align:right;">Position</th></tr></thead><tbody><tr><td style="text-align:right;"><code>bottom</code></td><td style="text-align:right;"><code>z = 0</code></td></tr><tr><td style="text-align:right;"><code>top</code></td><td style="text-align:right;"><code>z = Lz</code></td></tr></tbody></table><p>The 2D names <code>west</code>, <code>east</code>, <code>south</code> and <code>north</code> still refer to the x/y bounding planes in 3D.</p><h2 id="Periodic-axis-shorthand" tabindex="-1">Periodic axis shorthand <a class="header-anchor" href="#Periodic-axis-shorthand" aria-label="Permalink to &quot;Periodic axis shorthand {#Periodic-axis-shorthand}&quot;">​</a></h2><p>The parser supports:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Shorthand</th><th style="text-align:right;">Expands to</th></tr></thead><tbody><tr><td style="text-align:right;"><code>Boundary x periodic</code></td><td style="text-align:right;"><code>west</code> + <code>east</code></td></tr><tr><td style="text-align:right;"><code>Boundary y periodic</code></td><td style="text-align:right;"><code>south</code> + <code>north</code></td></tr></tbody></table><p>Use explicit face declarations for 3D z-periodicity in this branch.</p><h2 id="Parser-only-axisymmetric-aliases" tabindex="-1">Parser-only axisymmetric aliases <a class="header-anchor" href="#Parser-only-axisymmetric-aliases" aria-label="Permalink to &quot;Parser-only axisymmetric aliases {#Parser-only-axisymmetric-aliases}&quot;">​</a></h2><p>When <code>Module axisymmetric</code> is present, the parser can rewrite:</p><table tabindex="0"><thead><tr><th style="text-align:right;">Alias</th><th style="text-align:right;">Mapped to</th></tr></thead><tbody><tr><td style="text-align:right;"><code>z</code></td><td style="text-align:right;"><code>x</code></td></tr><tr><td style="text-align:right;"><code>wall</code></td><td style="text-align:right;"><code>north</code></td></tr><tr><td style="text-align:right;"><code>axis</code></td><td style="text-align:right;"><code>south</code></td></tr></tbody></table><p>However, <code>Module axisymmetric</code> is not a public runtime module in this branch: <code>run_simulation</code> rejects it. These aliases are documented only so old or development <code>.krk</code> files fail in an understandable way.</p><p>Source: <code>src/io/kraken_parser.jl</code>.</p>',17)])])}const x=e(o,[["render",r]]);export{y as __pageData,x as default};
